15	// Author: Brad Hyslop <bhyslop@scaleinvariant.org>
16	//
17	// RBTDRP — pristine-lifecycle fixture for theurge release qualification
18	//
19	// Case 1 (marshal-zero-attestation) is the entry gate for `rbw-tP`. It asserts
20	// that the working tree was just zeroed by `rbw-MZ` (rblm_zero) — five
21	// violation classes are checked and ALL surfaced in one aggregated diagnostic.
22	// Failure short-circuits subsequent cases via the per-fixture fail_fast switch.
23	
24	use std::path::{Path, PathBuf};
25	use std::process::Command;
26	
27	use crate::case;
28	use crate::rbtdre_engine::{rbtdre_Section, rbtdre_Verdict};
29	
30	/// Site-specific RBRR fields that rblm_zero blanks. These five fields define
31	/// the depot-bound site identity; an empty value is the post-marshal-zero
32	/// invariant.
33	const RBTDRP_RBRR_BLANK_FIELDS: &[&str] = &[
34	    "RBRR_DEPOT_PROJECT_ID",
35	    "RBRR_GAR_REPOSITORY",
36	    "RBRR_GCB_POOL_STEM",
37	    "RBRR_CLOUD_PREFIX",
38	    "RBRR_RUNTIME_PREFIX",
39	];
40	
41	/// Roles whose RBRA credential files rblm_zero deletes.
42	const RBTDRP_RBRA_ROLES: &[&str] = &["governor", "director", "retriever", "assay"];
43	
44	/// Nameplate hallmark fields rblm_zero blanks.
45	const RBTDRP_RBRN_BLANK_FIELDS: &[&str] = &["RBRN_SENTRY_HALLMARK", "RBRN_BOTTLE_HALLMARK"];
46	
47	/// File-relative constants matching rbbc_constants.sh / rbcc_Constants.sh.
48	const RBTDRP_DOT_DIR: &str = ".rbk";
49	const RBTDRP_RBRR_FILE: &str = ".rbk/rbrr.env";
50	const RBTDRP_RBRA_FILE: &str = "rbra.env";
51	const RBTDRP_RBRN_FILE: &str = "rbrn.env";
52	const RBTDRP_RBRV_FILE: &str = "rbrv.env";
53	
54	// ── Helpers ──────────────────────────────────────────────────
55	
56	/// Read an env file and return the value for `key`, or None if the key is
57	/// absent. The bash regime files use `KEY=value` lines (unquoted); comment
58	/// and blank lines are skipped. The trailing newline is stripped from value.
59	fn rbtdrp_read_env_value(path: &Path, key: &str) -> Option<String> {
60	    let content = std::fs::read_to_string(path).ok()?;
61	    let prefix = format!("{}=", key);
62	    for line in content.lines() {
63	        let trimmed = line.trim_start();
64	        if trimmed.starts_with('#') {
65	            continue;
66	        }
67	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
68	            return Some(rest.to_string());
69	        }
70	    }
71	    None
72	}
73	
74	/// Resolve a path that may be absolute or relative-to-project-root.
75	fn rbtdrp_resolve(root: &Path, raw: &str) -> PathBuf {
76	    if Path::new(raw).is_absolute() {
77	        PathBuf::from(raw)
78	    } else {
79	        root.join(raw)
80	    }
81	}
82	
83	/// Class A — working tree clean (`git status --porcelain` empty).
84	fn rbtdrp_check_tree_clean(root: &Path, violations: &mut Vec<String>) {
85	    match Command::new("git")
86	        .args(["status", "--porcelain"])
87	        .current_dir(root)
88	        .output()
89	    {
90	        Ok(out) if out.status.success() => {
91	            let stdout = String::from_utf8_lossy(&out.stdout);
92	            let trimmed = stdout.trim();
93	            if !trimmed.is_empty() {
94	                violations.push(format!(
95	                    "working tree not clean — uncommitted changes:\n{}",
96	                    trimmed
97	                ));
98	            }
99	        }
100	        Ok(out) => violations.push(format!(
101	            "git status --porcelain failed (exit {}): {}",
102	            out.status.code().unwrap_or(-1),
103	            String::from_utf8_lossy(&out.stderr).trim()
104	        )),
105	        Err(e) => violations.push(format!("git status invocation failed: {}", e)),
106	    }
107	}
108	
109	/// Class B — five site-specific RBRR fields are blank.
110	fn rbtdrp_check_rbrr_fields(rbrr: &Path, violations: &mut Vec<String>) {
111	    for field in RBTDRP_RBRR_BLANK_FIELDS {
112	        if let Some(value) = rbtdrp_read_env_value(rbrr, field) {
113	            if !value.is_empty() {
114	                violations.push(format!(
115	                    "RBRR field non-blank: {}={} (in {})",
116	                    field,
117	                    value,
118	                    rbrr.display()
119	                ));
120	            }
121	        }
122	    }
123	}
124	
125	/// Class C — no RBRA credential files at the four role paths.
126	fn rbtdrp_check_rbra_files(root: &Path, secrets_dir: &str, violations: &mut Vec<String>) {
127	    if secrets_dir.is_empty() {
128	        violations.push(
129	            "RBRR_SECRETS_DIR is blank — cannot resolve credential paths".to_string(),
130	        );
131	        return;
132	    }
133	    let secrets = rbtdrp_resolve(root, secrets_dir);
134	    for role in RBTDRP_RBRA_ROLES {
135	        let path = secrets.join(role).join(RBTDRP_RBRA_FILE);
136	        if path.exists() {
137	            violations.push(format!("RBRA credential present: {}", path.display()));
138	        }
139	    }
140	}
141	
142	/// Class D — every nameplate's RBRN_SENTRY_HALLMARK and RBRN_BOTTLE_HALLMARK
143	/// is blank.
144	fn rbtdrp_check_nameplate_hallmarks(root: &Path, violations: &mut Vec<String>) {
145	    let dot_dir = root.join(RBTDRP_DOT_DIR);
146	    let entries = match std::fs::read_dir(&dot_dir) {
147	        Ok(e) => e,
148	        Err(e) => {
149	            violations.push(format!("cannot read {}: {}", dot_dir.display(), e));
150	            return;
151	        }
152	    };
153	    for entry in entries.flatten() {
154	        let np_dir = entry.path();
155	        if !np_dir.is_dir() {
156	            continue;
157	        }
158	        let rbrn = np_dir.join(RBTDRP_RBRN_FILE);
159	        if !rbrn.exists() {
160	            continue;
161	        }
162	        for field in RBTDRP_RBRN_BLANK_FIELDS {
163	            if let Some(value) = rbtdrp_read_env_value(&rbrn, field) {
164	                if !value.is_empty() {
165	                    violations.push(format!(
166	                        "nameplate hallmark non-blank: {}={} (in {})",
167	                        field,
168	                        value,
169	                        rbrn.display()
170	                    ));
171	                }
172	            }
173	        }
174	    }
175	}
176	
177	/// Class E — every vessel rbrv.env has RBRV_RELIQUARY blank and every
178	/// RBRV_IMAGE_*_ANCHOR field blank.
179	fn rbtdrp_check_vessel_depot_fields(
180	    root: &Path,
181	    vessel_dir: &str,
182	    violations: &mut Vec<String>,
183	) {
184	    if vessel_dir.is_empty() {
185	        violations.push("RBRR_VESSEL_DIR is blank — cannot scan vessels".to_string());
186	        return;
187	    }
188	    let vroot = rbtdrp_resolve(root, vessel_dir);
189	    let entries = match std::fs::read_dir(&vroot) {
190	        Ok(e) => e,
191	        Err(e) => {
192	            violations.push(format!("cannot read {}: {}", vroot.display(), e));
193	            return;
194	        }
195	    };
196	    for entry in entries.flatten() {
197	        let v_dir = entry.path();
198	        if !v_dir.is_dir() {
199	            continue;
200	        }
201	        let rbrv = v_dir.join(RBTDRP_RBRV_FILE);
202	        if !rbrv.exists() {
203	            continue;
204	        }
205	        rbtdrp_scan_rbrv_file(&rbrv, violations);
206	    }
207	}
208	
209	/// Scan a single rbrv.env for non-blank RBRV_RELIQUARY and RBRV_IMAGE_*_ANCHOR
210	/// fields.
211	fn rbtdrp_scan_rbrv_file(rbrv: &Path, violations: &mut Vec<String>) {
212	    let content = match std::fs::read_to_string(rbrv) {
213	        Ok(c) => c,
214	        Err(e) => {
215	            violations.push(format!("cannot read {}: {}", rbrv.display(), e));
216	            return;
217	        }
218	    };
219	    for line in content.lines() {
220	        let trimmed = line.trim_start();
221	        if trimmed.starts_with('#') {
222	            continue;
223	        }
224	        let (key, value) = match trimmed.split_once('=') {
225	            Some(kv) => kv,
226	            None => continue,
227	        };
228	        let is_reliquary = key == "RBRV_RELIQUARY";
229	        let is_anchor = key.starts_with("RBRV_IMAGE_") && key.ends_with("_ANCHOR");
230	        if (is_reliquary || is_anchor) && !value.is_empty() {
231	            violations.push(format!(
232	                "vessel depot-scoped field non-blank: {}={} (in {})",
233	                key,
234	                value,
235	                rbrv.display()
236	            ));
237	        }
238	    }
239	}
240	
241	// ── Case ─────────────────────────────────────────────────────
242	
243	/// Case 1 — marshal-zero attestation. Aggregates all five violation classes
244	/// into a single diagnostic. A passing run is the proof that `rbw-MZ` was
245	/// just executed and committed.
246	fn rbtdrp_marshal_zero_attestation(_dir: &Path) -> rbtdre_Verdict {
247	    let root = match std::env::current_dir() {
248	        Ok(r) => r,
249	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot resolve project root: {}", e)),
250	    };
251	
252	    let rbrr = root.join(RBTDRP_RBRR_FILE);
253	    if !rbrr.exists() {
254	        return rbtdre_Verdict::Fail(format!("RBRR file not found: {}", rbrr.display()));
255	    }
256	
257	    let secrets_dir = rbtdrp_read_env_value(&rbrr, "RBRR_SECRETS_DIR").unwrap_or_default();
258	    let vessel_dir = rbtdrp_read_env_value(&rbrr, "RBRR_VESSEL_DIR").unwrap_or_default();
259	
260	    let mut violations: Vec<String> = Vec::new();
261	
262	    rbtdrp_check_tree_clean(&root, &mut violations);
263	    rbtdrp_check_rbrr_fields(&rbrr, &mut violations);
264	    rbtdrp_check_rbra_files(&root, &secrets_dir, &mut violations);
265	    rbtdrp_check_nameplate_hallmarks(&root, &mut violations);
266	    rbtdrp_check_vessel_depot_fields(&root, &vessel_dir, &mut violations);
267	
268	    if violations.is_empty() {
269	        return rbtdre_Verdict::Pass;
270	    }
271	
272	    let body = violations
273	        .iter()
274	        .map(|v| format!("  - {}", v))
275	        .collect::<Vec<_>>()
276	        .join("\n");
277	    rbtdre_Verdict::Fail(format!(
278	        "marshal-zero attestation failed — {} violation(s):\n{}\n\n\
279	         remedy: tt/rbw-MZ.MarshalZeroes.sh, then commit and rerun.",
280	        violations.len(),
281	        body
282	    ))
283	}
284	
285	// ── Section registry ─────────────────────────────────────────
286	
287	pub static RBTDRP_SECTIONS_PRISTINE_LIFECYCLE: &[rbtdre_Section] = &[rbtdre_Section {
288	    name: "pristine-lifecycle-gate",
289	    cases: &[case!(rbtdrp_marshal_zero_attestation)],
290	}];
