36	/// BUK dispatch output subdirectory — tabtargets write facts to BURV_OUTPUT_ROOT_DIR/current.
37	/// Matches BURD_OUTPUT_DIR = "${BURC_OUTPUT_ROOT_DIR}/current" from bud_dispatch.sh.
38	pub const RBTDRI_BURV_OUTPUT_SUBDIR: &str = "current";
39	
40	// ── Invocation result ────────────────────────────────────────
41	
42	/// Captured output from a tabtarget invocation.
43	#[derive(Debug)]
44	pub struct rbtdri_InvokeResult {
45	    pub stdout: String,
46	    pub stderr: String,
47	    pub exit_code: i32,
48	    pub burv_output: PathBuf,
49	}
