170	// ── Tabtarget invocation with BURV isolation ─────────────────
171	
172	/// Internal: execute a resolved tabtarget with BURV isolation and optional extra env vars.
173	fn rbtdri_invoke_impl(
174	    ctx: &mut rbtdri_Context,
175	    tabtarget: &Path,
176	    args: &[&str],
177	    extra_env: &[(&str, &str)],
178	) -> Result<rbtdri_InvokeResult, String> {
179	    let invoke_num = ctx.invoke_count;
180	    ctx.invoke_count += 1;
181	
182	    let invoke_dir = ctx.burv_root.join(format!("invoke-{:05}", invoke_num));
183	    let burv_output = invoke_dir.join("output");
184	    let burv_temp = invoke_dir.join("temp");
185	
186	    std::fs::create_dir_all(&burv_output)
187	        .map_err(|e| format!("rbtdri: failed to create BURV output dir: {}", e))?;
188	    std::fs::create_dir_all(&burv_temp)
189	        .map_err(|e| format!("rbtdri: failed to create BURV temp dir: {}", e))?;
190	
191	    let mut cmd = Command::new(tabtarget);
192	    cmd.args(args)
193	        .current_dir(&ctx.project_root)
194	        .env("BURV_OUTPUT_ROOT_DIR", &burv_output)
195	        .env("BURV_TEMP_ROOT_DIR", &burv_temp);
196	
197	    for (key, value) in extra_env {
198	        cmd.env(key, value);
199	    }
200	
201	    let output = cmd
202	        .output()
203	        .map_err(|e| format!("rbtdri: failed to execute '{}': {}", tabtarget.display(), e))?;
204	
205	    Ok(rbtdri_InvokeResult {
206	        stdout: String::from_utf8_lossy(&output.stdout).into_owned(),
207	        stderr: String::from_utf8_lossy(&output.stderr).into_owned(),
208	        exit_code: output.status.code().unwrap_or(-1),
209	        burv_output,
210	    })
