        eprintln!("Verifying crucible is inactive after quench...");
        match rbtdri_invoke_global(&mut ctx, RBTDRM_COLOPHON_CRUCIBLE_ACTIVE, &[fixture], &[]) {
            Ok(r) if r.exit_code != 0 => {
